const AuthContext = createContext(null);

const OIDC_CONFIG = {
  clientId: 'your-client-id',
  authorizationEndpoint: 'https://your-auth-server.com/oauth2/authorize',
  tokenEndpoint: 'https://your-auth-server.com/oauth2/token',
  redirectUri: window.location.origin + '/callback',
  scope: 'openid profile email',
  responseType: 'code',
  codeChallengeMethod: 'S256'
};

function generateRandomString(length) {
  const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  let result = '';
  const randomValues = new Uint8Array(length);
  crypto.getRandomValues(randomValues);
  for (let i = 0; i < length; i++) {
    result += charset[randomValues[i] % charset.length];
  }
  return result;
}

async function sha256(plain) {
  const encoder = new TextEncoder();
  const data = encoder.encode(plain);
  return await crypto.subtle.digest('SHA-256', data);
}

function base64UrlEncode(arrayBuffer) {
  const bytes = new Uint8Array(arrayBuffer);
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary)
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
}

function base64UrlDecode(str) {
  let base64 = str.replace(/-/g, '+').replace(/_/g, '/');
  while (base64.length % 4) {
    base64 += '=';
  }
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return new TextDecoder().decode(bytes);
}

function decodeIdToken(idToken) {
  const parts = idToken.split('.');
  if (parts.length !== 3) {
    throw new Error('Invalid ID token format');
  }
  
  const payload = parts[1];
  const decodedPayload = base64UrlDecode(payload);
  return JSON.parse(decodedPayload);
}

function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const storedUser = localStorage.getItem('user');
    const storedAccessToken = localStorage.getItem('access_token');
    const storedIdToken = localStorage.getItem('id_token');
    
    if (storedUser && storedAccessToken && storedIdToken) {
      setUser(JSON.parse(storedUser));
    }
    setLoading(false);
  }, []);

  const login = async () => {
    try {
      const state = generateRandomString(32);
      const codeVerifier = generateRandomString(128);
      
      sessionStorage.setItem('pkce_state', state);
      sessionStorage.setItem('pkce_code_verifier', codeVerifier);
      
      const hashed = await sha256(codeVerifier);
      const codeChallenge = base64UrlEncode(hashed);
      
      const params = new URLSearchParams({
        client_id: OIDC_CONFIG.clientId,
        redirect_uri: OIDC_CONFIG.redirectUri,
        response_type: OIDC_CONFIG.responseType,
        scope: OIDC_CONFIG.scope,
        state: state,
        code_challenge: codeChallenge,
        code_challenge_method: OIDC_CONFIG.codeChallengeMethod
      });
      
      window.location.href = `${OIDC_CONFIG.authorizationEndpoint}?${params.toString()}`;
    } catch (err) {
      setError(err.message);
    }
  };

  const handleCallback = async (code, state) => {
    try {
      const storedState = sessionStorage.getItem('pkce_state');
      const codeVerifier = sessionStorage.getItem('pkce_code_verifier');
      
      if (state !== storedState) {
        throw new Error('State mismatch - possible CSRF attack');
      }
      
      const tokenParams = new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: OIDC_CONFIG.redirectUri,
        client_id: OIDC_CONFIG.clientId,
        code_verifier: codeVerifier
      });
      
      const response = await fetch(OIDC_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: tokenParams.toString()
      });
      
      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error_description || 'Token exchange failed');
      }
      
      const tokens = await response.json();
      
      const userProfile = decodeIdToken(tokens.id_token);
      
      localStorage.setItem('access_token', tokens.access_token);
      localStorage.setItem('id_token', tokens.id_token);
      if (tokens.refresh_token) {
        localStorage.setItem('refresh_token', tokens.refresh_token);
      }
      localStorage.setItem('user', JSON.stringify(userProfile));
      
      sessionStorage.removeItem('pkce_state');
      sessionStorage.removeItem('pkce_code_verifier');
      
      setUser(userProfile);
      
      window.history.replaceState({}, document.title, '/');
    } catch (err) {
      setError(err.message);
      throw err;
    }
  };

  const logout = () => {
    localStorage.removeItem('access_token');
    localStorage.removeItem('id_token');
    localStorage.removeItem('refresh_token');
    localStorage.removeItem('user');
    setUser(null);
  };

  const value = {
    user,
    loading,
    error,
    login,
    logout,
    handleCallback,
    isAuthenticated: !!user
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within AuthProvider');
  }
  return context;
}

function CallbackPage() {
  const { handleCallback } = useAuth();
  const [error, setError] = useState(null);

  useEffect(() => {
    const processCallback = async () => {
      const params = new URLSearchParams(window.location.search);
      const code = params.get('code');
      const state = params.get('state');
      const errorParam = params.get('error');
      
      if (errorParam) {
        setError(params.get('error_description') || errorParam);
        return;
      }
      
      if (code && state) {
        try {
          await handleCallback(code, state);
        } catch (err) {
          setError(err.message);
        }
      } else {
        setError('Missing code or state parameter');
      }
    };
    
    processCallback();
  }, [handleCallback]);

  if (error) {
    return (
      <div style={{ padding: '20px', textAlign: 'center' }}>
        <h2>Authentication Error</h2>
        <p style={{ color: 'red' }}>{error}</p>
        <button onClick={() => window.location.href = '/'}>Go to Home</button>
      </div>
    );
  }

  return (
    <div style={{ padding: '20px', textAlign: 'center' }}>
      <h2>Processing authentication...</h2>
    </div>
  );
}

